    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Pilates for Seniors - 2w 3x/wk',
    'pilates',
    3,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Pilates for Seniors'
ON CONFLICT DO NOTHING;

